/// <summary>
/// Report Data provider class for - Elevator receipt report - Abhinav
/// </summary>
[SRSReportParameterAttribute(classStr(ETGElevatorReceiptReportContract))]
class ETGElevatorReceiptReportRDP extends SRSReportDataProviderBase
{
    ETGElevatorReceiptReportTmp etgElevatorReceiptReportTmp;

}

Method.Source:
[SRSReportDataSetAttribute(tableStr(ETGElevatorReceiptReportTmp))]
public ETGElevatorReceiptReportTmp getTmp()
{
    select etgElevatorReceiptReportTmp;
    return etgElevatorReceiptReportTmp;
}

public void processReport()
{
    ETGElevatorReceiptReportContract    contract = this.parmDataContract() as ETGElevatorReceiptReportContract;
    ETGElevatorReceiptNumber            elevatorreceiptNumber = contract.parmElevatorReceiptNumber();
    ETGElevatorReceiptTable             elevatorreceiptTable;


    select firstonly elevatorreceiptTable
        where elevatorreceiptTable.ElevatorReceiptNumber == elevatorreceiptNumber;

    if(elevatorreceiptTable)
    {
        etgElevatorReceiptReportTmp.clear();

        etgElevatorReceiptReportTmp.ElevatorReceiptNumber       = elevatorreceiptTable.ElevatorReceiptNumber;
        etgElevatorReceiptReportTmp.ETGElevatorReceiptType      = elevatorreceiptTable.ETGElevatorReceiptType;
        etgElevatorReceiptReportTmp.ReceiptDate                 = elevatorreceiptTable.ReceiptDate;
        etgElevatorReceiptReportTmp.DockagePercentage           = elevatorreceiptTable.DockagePercentage;
        etgElevatorReceiptReportTmp.DockageWeight               = elevatorreceiptTable.DockageWeight;
        etgElevatorReceiptReportTmp.SplitsPercentage            = elevatorreceiptTable.SplitsPercentage;
        etgElevatorReceiptReportTmp.SplitsWeight                = elevatorreceiptTable.SplitsWeight;
        etgElevatorReceiptReportTmp.ScaleTicketReferenceNumber  = elevatorreceiptTable.ScaleTicketReferenceNumber;
        etgElevatorReceiptReportTmp.GrossWeight                 = elevatorreceiptTable.GrossWeight;
        etgElevatorReceiptReportTmp.VehicleWeight               = elevatorreceiptTable.VehicleWeight;
        etgElevatorReceiptReportTmp.NetWeight                   = elevatorreceiptTable.NetWeight;
        etgElevatorReceiptReportTmp.Grain                       = InventTable::find(elevatorreceiptTable.Grain).itemName();
        etgElevatorReceiptReportTmp.GrainUnloadedWeight         = elevatorreceiptTable.GrainUnloadedWeight;
        etgElevatorReceiptReportTmp.StationName                 = elevatorreceiptTable.StationName;
        etgElevatorReceiptReportTmp.StationNumber               = elevatorreceiptTable.StationNumber;
        etgElevatorReceiptReportTmp.ReceiptReference            = elevatorreceiptTable.ReceiptReference;

        str AmountinTxt;
        AmountinTxt                                     =  numeralsToTxt_EN(etgElevatorReceiptReportTmp.GrainUnloadedWeight);
        AmountinTxt                                     = strReplace(AmountinTxt,'***','');
        AmountinTxt                                     = strReplace(AmountinTxt,'and 00/100','');
        etgElevatorReceiptReportTmp.GrainUnloadedInWords            = AmountinTxt;

        AmountinTxt                                     =  numeralsToTxt_EN(etgElevatorReceiptReportTmp.NetWeight);
        AmountinTxt                                     = strReplace(AmountinTxt,'***','');
        AmountinTxt                                     = strReplace(AmountinTxt,'and 00/100','');
        etgElevatorReceiptReportTmp.NetWeightInWords            = AmountinTxt;

        etgElevatorReceiptReportTmp.Grade = elevatorreceiptTable.Grade;

        switch(elevatorreceiptTable.ETGElevatorReceiptType)
        {
            case ETGElevatorReceiptType::SpecialBinPrimaryElevatorReceipt:
                etgElevatorReceiptReportTmp.ReceiptType1 = 1;
                break;
            case ETGElevatorReceiptType::InterimPrimaryElevatorReceipt:
                etgElevatorReceiptReportTmp.ReceiptType2 = 1;
                break;
            case ETGElevatorReceiptType::PrimaryElevatorReceipt:
                etgElevatorReceiptReportTmp.ReceiptType3 = 1;
                break;
            case ETGElevatorReceiptType::NonProducerPurchase:
                etgElevatorReceiptReportTmp.ReceiptType4 = 1;
                break;   
        }
        ETGCanadaParameters etgCanadaParameters;
        select firstonly etgCanadaParameters;
        etgElevatorReceiptReportTmp.Address = etgCanadaParameters.AddressForElevatorReceipt;

        etgElevatorReceiptReportTmp.insert();
    }
}
